--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1864,6 +1864,11 @@ static Value *simplifyAndOfICmps(ICmpInst *Op0, ICmpInst *Op1,
   if (Value *X = simplifyAndOfICmpsWithAdd(Op1, Op0, Q.IIQ))
     return X;

+  if (Value *X = simplifyAndOrOfICmpsWithAddOvf(Op0, Op1, true))
+    return X;
+  if (Value *X = simplifyAndOrOfICmpsWithAddOvf(Op1, Op0, true))
