+
   return nullptr;
 }

@@ -1914,6 +1919,73 @@ static Value *simplifyOrOfICmpsWithAdd(ICmpInst *Op0, ICmpInst *Op1,
   return nullptr;
 }

+/// Simplify (icmp ult/ugt (add A, B), A) | (icmp ult/ugt (add A, B), B)
+/// -> (icmp ult/ugt (add A, B), A)
+/// Similarly for AND with uge/ule.
+/// For unsigned addition, overflow occurs iff sum < operand (or equivalently
+/// operand > sum). Checking against either operand is sufficient.
+static Value *simplifyAndOrOfICmpsWithAddOvf(ICmpInst *Op0, ICmpInst *Op1,
+                                              bool IsAnd) {
+  // Both icmps must be unsigned
+  if (!Op0->isUnsigned() || !Op1->isUnsigned())
+    return nullptr;
+
+  ICmpInst::Predicate Pred0 = Op0->getPredicate();
+  ICmpInst::Predicate Pred1 = Op1->getPredicate();
+
+  // For OR: look for ult/ugt (overflow check)
+  // For AND: look for uge/ule (no overflow check)
+  if (IsAnd) {
+    if (Pred0 != ICmpInst::ICMP_UGE && Pred0 != ICmpInst::ICMP_ULE)
+      return nullptr;
+    if (Pred1 != ICmpInst::ICMP_UGE && Pred1 != ICmpInst::ICMP_ULE)
+      return nullptr;
+  } else {
+    if (Pred0 != ICmpInst::ICMP_ULT && Pred0 != ICmpInst::ICMP_UGT)
+      return nullptr;
+    if (Pred1 != ICmpInst::ICMP_ULT && Pred1 != ICmpInst::ICMP_UGT)
+      return nullptr;
+  }
+
+  // Find the add operation and its operands
+  Value *AddOp = nullptr;
+  Value *A = nullptr, *B = nullptr;
+
+  // Try to find (add A, B) in Op0
+  if (match(Op0->getOperand(0), m_Add(m_Value(A), m_Value(B))))
+    AddOp = Op0->getOperand(0);
+  else if (match(Op0->getOperand(1), m_Add(m_Value(A), m_Value(B))))
+    AddOp = Op0->getOperand(1);
+
+  if (!AddOp)
+    return nullptr;
+
+  // Check that Op1 also uses the same add
+  if (Op1->getOperand(0) != AddOp && Op1->getOperand(1) != AddOp)
+    return nullptr;
+
+  // Extract the operands being compared against the add operands
+  Value *Op0CmpOp = nullptr, *Op1CmpOp = nullptr;
+
+  // For Op0: get the operand that is not the add
+  if (Op0->getOperand(0) == AddOp)
+    Op0CmpOp = Op0->getOperand(1);
+  else
+    Op0CmpOp = Op0->getOperand(0);
+
+  // For Op1: get the operand that is not the add
+  if (Op1->getOperand(0) == AddOp)
+    Op1CmpOp = Op1->getOperand(1);
+  else
+    Op1CmpOp = Op1->getOperand(0);
+
+  // Check if the compared operands are A and B
+  if ((Op0CmpOp == A && Op1CmpOp == B) || (Op0CmpOp == B && Op1CmpOp == A))
+    return Op0;
+
+  return nullptr;
+}
+
 static Value *simplifyOrOfICmps(ICmpInst *Op0, ICmpInst *Op1,
                                 const SimplifyQuery &Q) {
   if (Value *X = simplifyUnsignedRangeCheck(Op0, Op1, /*IsAnd=*/false, Q))
@@ -1940,6 +2012,11 @@ static Value *simplifyOrOfICmps(ICmpInst *Op0, ICmpInst *Op1,
   if (Value *X = simplifyOrOfICmpsWithAdd(Op1, Op0, Q.IIQ))
     return X;

+  if (Value *X = simplifyAndOrOfICmpsWithAddOvf(Op0, Op1, false))
+    return X;
+  if (Value *X = simplifyAndOrOfICmpsWithAddOvf(Op1, Op0, false))
+    return X;
+
   return nullptr;
 }

