+  // Match unsigned add overflow check patterns:
+  // (icmp ult/ugt (add A, B), A) | (icmp ult/ugt (add A, B), B) -> single icmp
+  // (icmp uge/ule (add A, B), A) & (icmp uge/ule (add A, B), B) -> single icmp
+  // For unsigned addition, overflow occurs iff sum < operand (or equivalently
+  // operand > sum). Checking against either operand is sufficient.
+  Value *AddOp = nullptr;
+  Value *A = nullptr, *B = nullptr;
+  
+  // Try to find (add A, B) in LHS
+  if (match(LHS0, m_Add(m_Value(A), m_Value(B))))
+    AddOp = LHS0;
+  else if (match(LHS1, m_Add(m_Value(A), m_Value(B))))
+    AddOp = LHS1;
+  // Try to find (add A, B) in RHS
+  else if (match(RHS0, m_Add(m_Value(A), m_Value(B))))
+    AddOp = RHS0;
+  else if (match(RHS1, m_Add(m_Value(A), m_Value(B))))
+    AddOp = RHS1;
+
+  if (AddOp) {
+    // Handle OR patterns (overflow check)
+    // (icmp ult sum, A) | (icmp ult sum, B) -> (icmp ult sum, A)
+    // (icmp ugt A, sum) | (icmp ult sum, B) -> (icmp ugt A, sum)
+    // (icmp ult sum, A) | (icmp ugt B, sum) -> (icmp ult sum, A)
+    // (icmp ugt A, sum) | (icmp ugt B, sum) -> (icmp ugt A, sum)
+    if (!IsAnd && ICmpInst::isUnsigned(PredL) && ICmpInst::isUnsigned(PredR)) {
+      // Get the operands being compared against A and B for each icmp
+      Value *L1 = nullptr, *R1 = nullptr;
+      // For LHS: extract the operand being compared against the sum
+      if (LHS0 == AddOp)
+        L1 = LHS1;  // (icmp pred sum, X) -> X
+      else if (LHS1 == AddOp)
+        L1 = LHS0;  // (icmp pred X, sum) -> X
+      // For RHS: extract the operand being compared against the sum
+      if (RHS0 == AddOp)
+        R1 = RHS1;  // (icmp pred sum, X) -> X
+      else if (RHS1 == AddOp)
+        R1 = RHS0;  // (icmp pred X, sum) -> X
+      // Check if L1 and R1 are A and B (the add operands)
+      if (L1 && R1 && ((L1 == A && R1 == B) || (L1 == B && R1 == A)))
+        return LHS;
+    }
+    // Handle AND patterns (no overflow check)
+    // (icmp uge sum, A) & (icmp uge sum, B) -> (icmp uge sum, A)
+    // (icmp ule A, sum) & (icmp uge sum, B) -> (icmp ule A, sum)
+    // (icmp uge sum, A) & (icmp ule B, sum) -> (icmp uge sum, A)
+    // (icmp ule A, sum) & (icmp ule B, sum) -> (icmp ule A, sum)
+    if (IsAnd && ICmpInst::isUnsigned(PredL) && ICmpInst::isUnsigned(PredR)) {
+      // Get the operands being compared against A and B for each icmp
+      Value *L1 = nullptr, *R1 = nullptr;
+      // For LHS: extract the operand being compared against the sum
+      if (LHS0 == AddOp)
+        L1 = LHS1;  // (icmp pred sum, X) -> X
+      else if (LHS1 == AddOp)
+        L1 = LHS0;  // (icmp pred X, sum) -> X
+      // For RHS: extract the operand being compared against the sum
+      if (RHS0 == AddOp)
+        R1 = RHS1;  // (icmp pred sum, X) -> X
+      else if (RHS1 == AddOp)
+        R1 = RHS0;  // (icmp pred X, sum) -> X
+      // Check if L1 and R1 are A and B (the add operands)
+      if (L1 && R1 && ((L1 == A && R1 == B) || (L1 == B && R1 == A)))
+        return LHS;
+    }
   }

   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
 }
